mapper.select:
SELECT companyNumber, companyName, companyAddress, filePath, compType, compSummary, compPageDate, cat1IsHiring, cat2IsHiring, cat3IsHiring, cat4IsHiring FROM ( SELECT ROW_NUMBER() OVER (
ORDER BY C.COMPANY_NAME ASC, C.COMPANY_NUMBER DESC ORDER BY CI.COMP_PAGE_DATE DESC, C.COMPANY_NUMBER DESC
) AS rowNum, C.COMPANY_NUMBER AS companyNumber, C.COMPANY_NAME AS companyName, C.COMPANY_ADDRESS AS companyAddress, CI.COMP_IMAGE_PATH AS filePath, CI.COMP_TYPE AS compType, CI.COMP_SUMMARY AS compSummary, TO_CHAR(CI.COMP_PAGE_DATE, 'YYYY-MM-DD') AS compPageDate, NVL(JP.CAT1_IS_HIRING, 0) AS cat1IsHiring, NVL(JP.CAT2_IS_HIRING, 0) AS cat2IsHiring, NVL(JP.CAT3_IS_HIRING, 0) AS cat3IsHiring, NVL(JP.CAT4_IS_HIRING, 0) AS cat4IsHiring FROM TBL_COMPANY C JOIN TBL_COMP_INFO CI ON C.COMPANY_NUMBER = CI.COMPANY_NUMBER LEFT JOIN TBL_JOB_POST JP ON C.COMPANY_NUMBER = JP.COMPANY_NUMBER WHERE C.COMPANY_STATE = '승인'
AND NVL(JP.CAT1_IS_HIRING, 0) = 1 AND NVL(JP.CAT2_IS_HIRING, 0) = 1 AND NVL(JP.CAT3_IS_HIRING, 0) = 1 AND NVL(JP.CAT4_IS_HIRING, 0) = 1
) WHERE rowNum BETWEEN #{startRow} AND #{endRow}
